// Dart教程 - 简介与环境搭建
// 示例代码

fn main() {
    println!("Hello, Dart教程!");

    // 变量声明
    let name = "World";
    let count = 0;

    // 输出
    println!("Hello, {}", name);

    // 条件判断
    let max = if count > 0 { count } else { 1 };

    println!("Max: {}", max);
}

